#!/usr/bin/env python3
"""
deploy_v19_34_223.py - Windows pusher L2 cap -> env-driven (MAX_L2_SLOTS).

Replaces the hardcoded 3-slot L2 cap in documents/scripts/ib_data_pusher.py with
a single env knob `_MAX_L2_SLOTS = int(os.environ.get("MAX_L2_SLOTS","3"))`,
matching the backend (services/l2_router.py). Commits to the repo so you can
`git pull` it on the WINDOWS box.

NOTE: raising above 3 ALSO needs an IB market-depth entitlement that allows it.
Paper accounts historically returned Error 309 at 5. If IB rejects the extras,
the backend l2-router status shows `cap_rejections` / `last_cap_skipped`.

Content-marker guarded (NOT sha) because the pusher file is shared with Windows:
  - already has the v223 env line  -> skip
  - still has `MAX_L2_SUBSCRIPTIONS = 3` (original) -> replace
  - neither -> abort WITHOUT changes.

RUN ON THE DGX:
  curl -s https://paste.rs/XXXXX -o /tmp/deploy_v19_34_223.py
  python3 /tmp/deploy_v19_34_223.py
"""
import os, base64, shutil, subprocess, sys, py_compile

REPO=os.path.expanduser("~/Trading-and-Analysis-Platform")
if not os.path.isdir(REPO): REPO=os.getcwd()
SVC=os.path.join(REPO,"documents","scripts","ib_data_pusher.py")
ENVMARK='_MAX_L2_SLOTS = max(1, int(os.environ.get("MAX_L2_SLOTS"'
ORIG='MAX_L2_SUBSCRIPTIONS = 3'
B64=""


def fail(m):
    print("\n[FAIL] "+m); sys.exit(1)


def main():
    print("== deploy_v19_34_223 ==\nrepo: "+REPO)
    if not os.path.isfile(SVC): fail("target not found: "+SVC)
    cur=open(SVC,"rb").read(); txt=cur.decode("utf-8","ignore")
    new_bytes=base64.b64decode(B64)
    if ENVMARK in txt:
        print("[ok] pusher already env-driven (v223) - skip write.")
    elif ORIG in txt:
        shutil.copy2(SVC,SVC+".v223.bak"); open(SVC,"wb").write(new_bytes)
        try:
            py_compile.compile(SVC,doraise=True)
        except py_compile.PyCompileError as e:
            shutil.copy2(SVC+".v223.bak",SVC); fail("py_compile failed, rolled back: "+str(e))
        os.remove(SVC+".v223.bak")
        print("[ok] ib_data_pusher.py L2 cap -> env-driven + compiles clean.")
    else:
        fail("ib_data_pusher.py matches NEITHER the original cap NOR the v223 "
             "marker - drift, aborting WITHOUT changes.")

    print("\n== git commit + push ==")
    subprocess.run(["git","add","-A"],cwd=REPO)
    cm=subprocess.run(["git","commit","-m",
        "v19.34.223 Windows pusher: L2 cap env-driven via MAX_L2_SLOTS "
        "(matches backend l2_router); default 3"],cwd=REPO)
    if cm.returncode==0:
        subprocess.run(["git","push"],cwd=REPO); print("[ok] committed + pushed.")
    else:
        print("[info] nothing to commit.")

    print("\n[DONE] Pusher change is on GitHub. NOW ON THE WINDOWS BOX:")
    print("  1. cd <repo>  &&  git pull")
    print("  2. set the env BEFORE starting the pusher:")
    print("       PowerShell:  $env:MAX_L2_SLOTS = '6'")
    print("       (or cmd:     set MAX_L2_SLOTS=6 )")
    print("  3. restart the pusher (the .bat / python ib_data_pusher.py you normally run)")
    print("  4. back on the DGX, watch for IB-309 caps:")
    print("       curl -s localhost:8001/api/ib/l2-router-status | python3 -m json.tool")
    print("     If cap_rejections climbs / last_cap_skipped non-empty -> IB is")
    print("     capping below 6 (Error 309); your paper acct likely allows only 3.")


if __name__=="__main__":
    main()
